import { useEffect } from "react";
import { useLocation } from "react-router-dom";
import Header from "@/components/landing/Header";
import Hero from "@/components/landing/Hero";
import Marquee from "@/components/landing/Marquee";
import MarketPreview from "@/components/landing/MarketPreview";
import StatsBento from "@/components/landing/StatsBento";
import Features from "@/components/landing/Features";
import HowItWorks from "@/components/landing/HowItWorks";
import FAQ from "@/components/landing/FAQ";
import CTA from "@/components/landing/CTA";
import Footer from "@/components/landing/Footer";
import RecentlyViewed from "@/components/landing/RecentlyViewed";
import WhatsChanged from "@/components/landing/WhatsChanged";

export default function LandingPage() {
  const { hash } = useLocation();

  // Scroll to in-page anchors after the page mounts. We need this because
  // AnimatePresence remounts the page tree on every pathname change, so
  // the browser's default hash-scroll fires before the target element
  // exists in the DOM.
  useEffect(() => {
    if (!hash) return;
    const id = hash.slice(1);
    const tryScroll = (attempt = 0) => {
      const el = document.getElementById(id);
      if (el) el.scrollIntoView({ behavior: "smooth", block: "start" });
      else if (attempt < 10) requestAnimationFrame(() => tryScroll(attempt + 1));
    };
    const t = setTimeout(tryScroll, 80);
    return () => clearTimeout(t);
  }, [hash]);

  return (
    <div data-testid="landing-page" className="min-h-screen bg-bg-base text-white font-body relative">
      <Header />
      <main>
        <Hero />
        <WhatsChanged />
        <Marquee />
        <MarketPreview />
        <StatsBento />
        <Features />
        <HowItWorks />
        <RecentlyViewed />
        <FAQ />
        <CTA />
      </main>
      <Footer />
    </div>
  );
}
